import React, { useState, useEffect } from 'react';
import { apiService } from '../../services/api';
import './BusinessesPage.css';

export default function BusinessesPage() {
  const [businesses, setBusinesses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [categoryName, setCategoryName] = useState('');

  useEffect(() => {
    const fetchBusinesses = async () => {
      const urlParams = new URLSearchParams(window.location.search);
      const cityId = urlParams.get('cityId');
      const categoryId = urlParams.get('categoryId');
      const categoryName = urlParams.get('categoryName') || '';

      setCategoryName(decodeURIComponent(categoryName));

      if (!categoryId) {
        setError('Category ID is required');
        setLoading(false);
        return;
      }

      setLoading(true);
      try {
        let response;
        const params = {};

        if (cityId) {
          params.cityId = cityId;
        }

        response = await apiService.businesses.getByCategory(categoryId, params);

        const businessesArray = Array.isArray(response.data)
          ? response.data
          : (response.data?.businesses || response.data?.data || []);

        setBusinesses(businessesArray);
      } catch (err) {
        console.error('Error fetching businesses:', err);
        setError('Failed to fetch businesses. Please try again.');
      } finally {
        setLoading(false);
      }
    };

    fetchBusinesses();
  }, []);

  if (loading) {
    return (
      <div className="businesses-page">
        <div className="container">
          <div className="loading">Loading businesses...</div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="businesses-page">
        <div className="container">
          <div className="error">{error}</div>
        </div>
      </div>
    );
  }

  return (
    <div className="businesses-page">
      <div className="container">
        <div className="businesses-header">
          <h1>{categoryName || 'Businesses'}</h1>
          <p className="results-count">{businesses.length} businesses found</p>
        </div>

        {businesses.length === 0 ? (
          <div className="no-results">
            <p>No businesses found for this category.</p>
          </div>
        ) : (
          <div className="businesses-grid">
            {businesses.map((business) => (
              <div key={business.id || business._id || business.companyId} className="business-card">
                <div className="business-card-image">
                  <img
                    src={business.image || business.logo || business.profileImage || './img/product-images/default.jpg'}
                    alt={business.name || business.companyName || business.businessName}
                  />
                </div>
                <div className="business-card-content">
                  <h3 className="business-name">
                    {business.name || business.companyName || business.businessName}
                  </h3>
                  <p className="business-category">
                    {business.categoryName || business.category?.name || categoryName}
                  </p>
                  <p className="business-location">
                    {business.cityName || business.city?.name || business.districtName || business.district?.name}
                  </p>
                  {business.address && (
                    <p className="business-address">{business.address}</p>
                  )}
                  {business.phone && (
                    <p className="business-phone">{business.phone}</p>
                  )}
                  {business.rating && (
                    <div className="business-rating">
                      <span className="rating-stars">{'★'.repeat(Math.floor(business.rating))}</span>
                      <span className="rating-value">{business.rating}</span>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
